(1, 43, NULL, 'textbook', 'cengage-jee-advanced-trignometry', 'CENGAGE JEE ADVANCED TRIGNOMETRY', '<p>Testt</p>\r\n', 1, 0, 39, '1', NULL, NULL, NULL, 0, 0.00, 605.00, 659.00, 0.00, '9789355735850', 48209010, NULL, 0, '0.00', '0.00', '0.00', '109.99', 'Reference Books-text book-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE ADVANCED TRIGNOMETRY', 'Reference Books-text book-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE ADVANCED TRIGNOMETRY', 'Reference Books-text book-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE ADVANCED TRIGNOMETRY', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 2, '2026-02-28 05:39:28', '2026-03-02 09:11:35', 'TB-4416', '<p>[]</p>\r\n'),
(2, 43, NULL, 'textbook', 'cengage-jee-coordinate-geometry', 'CENGAGE JEE COORDINATE GEOMETRY', '<h1>CENGAGE JEE COORDINATE GEOMETRY</h1>\r\n', 1, 0, 39, '1', NULL, NULL, NULL, 0, 0.00, 1.00, 869.00, 0.00, '9789355735874', 48209010, NULL, 0, '0.00', '0.00', '0.00', '0.00', 'text book-Reference Books-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE COORDINATE GEOMETRY', 'text book-Reference Books-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE COORDINATE GEOMETRY', 'text book-Reference Books-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE COORDINATE GEOMETRY', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 3, '2026-02-28 05:39:28', '2026-03-02 09:11:37', 'TB-4417', '<h1>CENGAGE JEE COORDINATE GEOMETRY</h1>\r\n'),
(3, 43, NULL, 'textbook', 'cengage-jee-vectors-and-3d-geometry', 'CENGAGE JEE VECTORS AND 3D GEOMETRY', '<p style=\"text-align:start;\"><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">Features the following types of problems:</span></p>\n<p><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">1. Single Correct Answer Type</span></p>\n<p style=\"text-align:start;\"><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">2. Multiple Correct Answers Type</span></p>\n<p style=\"text-align:start;\"><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">3. Linked Comprehension Type</span></p>\n<p style=\"text-align:start;\"><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">4. Matrix Match Type</span></p>\n<p style=\"text-align:start;\"><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">5. Numerical Value Type (including Integer Answer Type)</span></p>\n<p style=\"text-align:start;\"><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">6. JEE (Main) PYQs – 2023 (Session 1) – Chapterwise Qs along with topic name tags</span></p>\n<p style=\"text-align:start;\"><span style=\"color: rgb(15,17,17);background-color: rgb(255,255,255);font-size: 14px;font-family: Amazon Ember;\">7. JEE (Advanced) PYQs – 2010-22 Qs</span>&nbsp;</p>\n', 1, 0, 39, '1', NULL, NULL, NULL, 0, 0.00, 605.00, 669.00, 0.00, '9789355735867', 48209010, '9789355735867', 0, '', '', '', '', 'REFERENCE BOOK-TEXTBOOK-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE VECTORS AND 3D GEOMETRY', 'REFERENCE BOOK-TEXTBOOK-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE VECTORS AND 3D GEOMETRY', 'REFERENCE BOOK-TEXTBOOK-CENGAGE LEARN PUBLICATIONS -CBSE-Eng,maths,science-CENGAGE JEE VECTORS AND 3D GEOMETRY', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 4, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
