(238, 43, NULL, 'textbook', 'ncert-textbook-class-5-english-marigold', 'NCERT TEXTBOOK CLASS 5 ENGLISH MARIGOLD', '<p><span style=\"color: rgb(51,51,51);background-color: rgb(255,255,255);font-size: 14px;font-family: Roboto, sans-serif;\">English is one of the most important subjects of the Class 5 CBSE curriculum. It is imperative for young learners to develop their spoken English as well as writing skills in this subject at the onset of their academic life. Having a solid foundation in the subject and a strong grammatical base makes it easier for students to understand and progress to higher classes with ease.</span>&nbsp;</p>\n', 1, 0, 368, '1', NULL, NULL, NULL, 0, 0.00, 65.00, 65.00, 0.00, '526', 49011010, '526', 0, '', '', '', '', 'NCERT TEXTBOOK CLASS 5 ENGLISH MARIGOLD', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 239, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
