(284, 43, NULL, 'textbook', 'arihant-a-problem-book-in-mathematical-analysis', 'ARIHANT A PROBLEM BOOK IN MATHEMATICAL ANALYSIS', '<ol>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">The Classic Texts Series is only one of its kind selections of classic pieces that started off as a bestseller and continues to be the same today as well. These classic texts have been designed to work as elementary textbooks, which help the students in building the concepts to prepare for various competitive examinations.</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">The newly updated edition of ‘A Problem in Mathematical Analysis’ presents a collection of problems and exercises that are systematically selected and arranged in compliance with the major sections of the course in mathematical analysis. This book does not contain any theoretical content but contains large number of problems for the purpose of thorough practice of the various concepts covered under the sphere of mathematical analysis. Before problems on mathematics, necessary information has also been given.  The more difficult problems have been supplied with hints and their solutions can be found in the answers section. As the book covers the varied aspects of Mathematical Analysis with the help of ample number of examples and practice questions, it for sure will serve as a complete textbook for practicing the various elements of Mathematical Analysis. This book inculcates:</span></li>\n</ol>\n<ul>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">The Classical Text series ‘best seller’ – collection of classic pieces of work</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Works as elementary text book building up the basic concepts</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Explanation of various concepts of Mathematics</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Divided into 16 Chapters</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Each chapter carries theoretical explanations and unsolved practice exercise</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Chapter wise study notes along with Miscellaneous examples,</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Covers aspects of Mathematical Analysis with the help of ample number of examples and practice questions</span>&nbsp;</li>\n</ul>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 225.00, 250.00, 0.00, '9789388127325', 49011010, '9789388127325', 0, '', '', '', '', 'ARIHANT A PROBLEM BOOK IN MATHEMATICAL ANALYSIS', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 285, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
(285, 43, NULL, 'textbook', 'arihant-46-years-solved-papers-iit-jee-main-advanced-physics', 'ARIHANT 46 YEARS SOLVED PAPERS IIT JEE (MAIN & ADVANCED) PHYSICS', '<p><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">For an impeccable practice of JEE questions, the revised edition of “46 YEARS’ CHAPTERWISE TOPIC WISE SOLVED PAPERS IIT JEE- PHYSICS” is categorized as the best-selling study material to crack JEE Exam 2023. Providing as a one-stop solution, this book is strictly prepared according to the board syllabus. It covers questions of JEE Advanced Mathematics from 1978-2023 in a chapter-wise and Topicwise format. As a self-assessment tool for exam preparation, Previous Years’ Solved Papers (2023-20133) of JEE Main &amp; Advanced Exams are included in the book. Accompanied by detailed solutions, the solved papers are well-supported with diagrams, Charts &amp; Tables for an in-depth understanding. Practicing with this book provides great help in covering crucial concepts of Mathematics.</span></p>\n<ul>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">A comprehensive book with chapterwise Topicwise solved papers</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">46 years (2023-1978) solved papers with detailed solutions</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">JEE Main &amp; Advanced Solved Paper (2023-2013)</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Builds the concepts deeply for a better understanding</span>&nbsp;</li>\n</ul>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 675.00, 750.00, 0.00, '97899358893465', 49011010, '97899358893465', 0, '', '', '', '', 'SOLVED PAPERS-ARIHANT PUBLICA-CBSE-PHYSICS-ARIHANT 46 YEARS SOLVED PAPERS IIT JEE (MAIN & ADVANCED) PHYSICS', 'SOLVED PAPERS-ARIHANT PUBLICA-CBSE-PHYSICS-ARIHANT 46 YEARS SOLVED PAPERS IIT JEE (MAIN & ADVANCED) PHYSICS', 'SOLVED PAPERS-ARIHANT PUBLICA-CBSE-PHYSICS-ARIHANT 46 YEARS SOLVED PAPERS IIT JEE (MAIN & ADVANCED) PHYSICS', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 286, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
