(335, 43, NULL, 'textbook', 'arihant-all-in-one-class-10-hindi-b', 'ARIHANT ALL IN ONE CLASS 10 HINDI B', '<p><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">कक्षा 10 हिंदी \'ब\' विशेष रूप से उन विद्यार्थियों के लिए तैयार की गई है जो CBSE पाठ्यक्रम के अनुसार कक्षा 10 में अध्ययनरत हैं | अनुभवी शिक्षकों व परीक्षकों द्वारा लिखी गयी इस पुस्तक में वस सभी अध्ययन सामग्री दी गई है जो विद्यार्थियों को परीक्षा में पूछे जाने वाले सभी प्रकार के प्रश्नों को हल कराने में समर्थ है व अंततः परीक्षा में उन्हें सम्पूर्ण सफलता दिलाने में सहायक होगी |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्यक्रम के अनुसार, इस पुस्तक में सभी खण्डों; अपठित बोध, व्याकरण, पाठ्यपुस्तक (स्पर्श भाग-2) व पूरक पाठ्यपुस्तक (संचयन भाग-2) तथा लेखन से संबंधित पाठ्य सामग्री दी गयी है |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">प्रत्येक खंड के आरम्भ में संबंधित अध्याय का सम्पूर्ण परिचय, उसमें से पूछे जाने वाले प्रश्न की प्रकृति, साघित उदाहरण तथा परीक्षा से संबंधित प्रश्न दिए गए हैं | ये सभी विद्यार्थियों को सम्पूर्ण अभ्यास कराने में सक्षम है |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्य सामग्री के अध्ययन व अभ्यास के साथ-साथ विद्यार्थियों को अभ्यास मूल्यांकन कराने के लिए भी पुस्तक में उचित सामग्री उपलब्ध है | सम्पूर्ण अभ्यास के लिए पुस्तक के अंत में 5 प्रतिदर्श प्रश्न-पत्र दिए गए हैं |</span>&nbsp;</p>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 315.00, 350.00, 0.00, '9789326196918', 49011010, '9789326196918', 0, '', '', '', '', 'ARIHANT ALL IN ONE CLASS 10 HINDI B', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 336, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
(336, 43, NULL, 'textbook', 'arihant-all-in-one-class-10-hindi-a', 'ARIHANT ALL IN ONE CLASS 10 HINDI A', '<p><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">कक्षा 10 हिंदी ‘अ’ विशेष रूप से उन विद्यार्थियों के लिए तैयार की गई है जो CBSE पाठ्यक्रम के अनुसार कक्षा- 10 में अध्ययनरत हैं | अनुभवी शिक्षकों व परीक्षकों द्वारा लिखी गई इस पुस्तक में वह सभी अध्ययन सामग्री दी गई है जो विद्यार्थियों को सभी प्रकार के प्रश्नों को हल कराने में समर्थ है व अंततः परीक्षा में उन्हें सम्पूर्ण सफलता दिलाने में सहायक होगी |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्यक्रम के अनुसार, इस पुस्तक को चार खण्डों; अपठित बोध, व्याकरण, पाठ्यपुस्तक (क्षितिज भाग 2) व पूरक पाठ्यपुस्तक (कृतिका भाग- 2) तथा लेखन के संबंधित सामग्री दी गई है |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">प्रत्येक खंड के आरम्भ में संबंधित अध्याय का सम्पूर्ण परिचय, उसमें से पूछे जाने वाले प्रश्न की प्रकृति, साघित उदाहरण तथा परीक्षा से संबंधित प्रश्न दिए गए हैं | ये सभी प्रश्न विद्यार्थियों को सम्पूर्ण अभ्यास कराने में सक्षम है एवं पुस्तक में दिए गए सभी प्रश्नों के सम्पूर्ण उत्तर दिया गया है |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्य- सामग्री के अध्ययन के साथ- साथ विद्यार्थियों को मूल्यांकन करने के लिए भी पुस्तक में उचित सामग्री उपलब्ध है | पुस्तक के अंत में 5 प्रतिदर्श प्रश्न-पत्र दिए गए हैं |</span>&nbsp;</p>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 315.00, 350.00, 0.00, '9789326196901', 49011010, '9789326196901', 0, '', '', '', '', 'ARIHANT ALL IN ONE CLASS 10 HINDI A', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 337, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL);
