(341, 43, NULL, 'textbook', 'arihant-all-in-one-class-9-sanskrit', 'ARIHANT ALL IN ONE CLASS 9 SANSKRIT', '<p><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">कक्षा 9 संस्कृतम विशेष रूप से उन विद्यार्थियों के लिए तैयार की गई है जो CBSE पाठ्यक्रम के अनुसार कक्षा- 9 में अध्ययनरत हैं | अनुभवी शिक्षकों व परीक्षकों द्वारा लिखी गई इस पुस्तक में वह सभी अध्ययन सामग्री दी गई है जो विद्यार्थियों को सभी प्रकार के प्रश्नों को हल कराने में समर्थ है व अंततः परीक्षा में उन्हें सम्पूर्ण सफलता दिलाने में सहायक होगी |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्यक्रम के अनुसार, इस पुस्तक को चार खण्डों; खंड \'क\'- अपठित अवबोधनम, खंड \'ख\'- रचनात्मक- कार्यम, खंड \'ग\'- अनुप्रयुक्त- व्याकरणम तथा खंड \'घ\'- पठित - बोधनम में बांटा गया है |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">प्रत्येक खंड के आरम्भ में संबंधित अध्याय का सम्पूर्ण परिचय, उसमें से पूछे जाने वाले प्रश्न की प्रकृति, साघित उदाहरण तथा परीक्षा से संबंधित प्रश्न दिए गए हैं | ये सभी प्रश्न विद्यार्थियों को सम्पूर्ण अभ्यास कराने में सक्षम है एवं पुस्तक में दिए गए सभी प्रश्नों के सम्पूर्ण उत्तर दिया गया है |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्य- सामग्री के अध्ययन के साथ- साथ विद्यार्थियों को मूल्यांकन करने के लिए भी पुस्तक में उचित सामग्री उपलब्ध है | पुस्तक के अंत में 5 प्रतिदर्श प्रश्न-पत्र दिए गए हैं |</span>&nbsp;</p>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 202.50, 225.00, 0.00, '9789326196697', 49011010, '9789326196697', 0, '', '', '', '', 'ARIHANT ALL IN ONE CLASS 9 SANSKRIT', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 342, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
