(345, 43, NULL, 'textbook', 'arihant-all-in-one-class-9-hindi-b', 'ARIHANT ALL IN ONE CLASS 9 HINDI B', '<p><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">हिंदी ‘ब’   कक्षा 9 विशेष रूप से उन विद्यार्थियों के लिए तौयार की गई है जो CBSE पाठ्यक्रम के अनुसार कक्षा 9 में अध्ययनरत हैं | अनुभवी शिक्षक व परीक्षक द्वारा लिखी गई इस पुस्तक में वह सामग्री दी गई है जो विद्यार्थियों के सभी प्रश्नों की हल करने में समर्थ है व अंततः परीक्षा में उन्हें सम्पूर्ण सफलता दिलाने में सहायक होगी|</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्यक्रम के अनुसार, इस पुस्तक में सभी खण्डों; खंड \'क\'- अपठित बोध, खंड \'ख\'- व्यावहारिक व्याकरण, खंड \'ग\'- पाठ्यपुस्तक (स्पर्श भाग-1) व पूरक पाठ्यपुस्तक (संचयन  भाग-1) तथा खंड \'घ\'- लेखन में बाँटा गया है|</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">प्रत्येक खंड के आरम्भ में संबंधित अध्याय का सम्पूर्ण परिचय, उसमें से पूछे जाने वाले प्रश्न की प्रकृति, साघित उदाहरण, तथा परीक्षा से संबंधित प्रश्न दिए गए हैं | ये सभी विद्यार्थियों को सम्पूर्ण अभ्यास कराने में सक्षम हैं |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्य सामग्री के अध्ययन व अभ्यास के साथ- साथ विद्यार्थियों को अभ्यास मूल्यांकन कराने के लिए भी पुस्तक में उचित सामग्री उपलब्ध है | पुस्तक के अंत में 5 प्रतिदर्श प्रश्न-पत्र दिए गए हैं |</span>&nbsp;</p>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 292.50, 325.00, 0.00, '9789326196680', 49011010, '9789326196680', 0, '', '', '', '', 'ARIHANT ALL IN ONE CLASS 9 HINDI B', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 346, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
(346, 43, NULL, 'textbook', 'arihant-all-in-one-class-9-hindi-a', 'ARIHANT ALL IN ONE CLASS 9 HINDI A', '<p><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">हिंदी ‘अ’   कक्षा 9 विशेष रूप से उन विद्यार्थियों के लिए तौयार की गई है जो CBSE पाठ्यक्रम के अनुसार कक्षा 9 में अध्ययनरत हैं | अनुभवी शिक्षक व परीक्षक द्वारा लिखी गई इस पुस्तक में वह सामग्री दी गई है जो विद्यार्थियों के सभी प्रश्नों की हल करने में समर्थ है व अंततः परीक्षा में उन्हें सम्पूर्ण सफलता दिलाने में सहायक होगी|</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्यक्रम के अनुसार, इस पुस्तक में सभी खण्डों; खंड \'क\'- अपठित बोध, खंड \'ख\'- व्यावहारिक व्याकरण, खंड \'ग\'- पाठ्यपुस्तक (क्षितिज भाग-1) व पूरक पाठ्यपुस्तक (कृतिका  भाग-1) तथा खंड \'घ\'- लेखन में बाँटा गया है|</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">प्रत्येक खंड के आरम्भ में संबंधित अध्याय का सम्पूर्ण परिचय, उसमें से पूछे जाने वाले प्रश्न की प्रकृति, साघित उदाहरण, तथा परीक्षा से संबंधित प्रश्न दिए गए हैं | ये सभी विद्यार्थियों को सम्पूर्ण अभ्यास कराने में सक्षम हैं |</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">पाठ्य सामग्री के अध्ययन व अभ्यास के साथ- साथ विद्यार्थियों को अभ्यास मूल्यांकन कराने के लिए भी पुस्तक में उचित सामग्री उपलब्ध है | पुस्तक के अंत में 3 प्रतिदर्श प्रश्न-पत्र दिए गए हैं |</span>&nbsp;</p>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 360.00, 400.00, 0.00, '9789326196673', 49011010, '9789326196673', 0, '', '', '', '', 'ARIHANT ALL IN ONE CLASS 9 HINDI A', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 347, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
(347, 43, NULL, 'textbook', 'arihant-all-in-one-class-9-english-language-literature', 'ARIHANT ALL IN ONE CLASS 9 ENGLISH LANGUAGE & LITERATURE', '<ol>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Arihant’s “All in One” is no new name today. One of the Best-Selling Series that is helping students with their school and board exams preparation by providing Complete Theory, Practice, and Assessment as per new issued pattern for the excellent academic results.</span><br><br><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">The freshly updated 2022-23 edition of “All in One English Language &amp; Literature for Class 9” is a self–study guide that has been carefully and consciously revised by providing proper explanation &amp; guidance and strictly following the latest CBSE Syllabus as prescribed by the Board. It has been written in such a way that the students will be fully guided to prepare for the exams in the most effective manner and secure higher grades. It constitutes all the key concepts in each distinctive chapter in an explanatory manner for a better understanding. The book not only focuses on imparting theoretical knowledge but also on enhancing the revision and practice level. It has all the materials required for Learning, Understanding, Practice &amp; Assessment and will surely guide the students on the way to success. This book inhibits:</span><br> <span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">‘All in One’ - Best Selling Series from class 6th -12th</span></li>\n</ol>\n<ul>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Covers complete theory, Practice, and Assessment of English Language &amp; Literature for Class 9 with solved examples</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Divided into 3 sections giving full coverage to the syllabus</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Each chapter is supported by detailed theory, illustrations, and all types of questions</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Special focus on New Pattern Objective Questions</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Every chapter accompanies Chapter Practice for quick revision</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Supplemented with all types of questions</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Assertion- Reason and Case-Based Questions</span></li>\n<li><span style=\"color: rgb(33,37,41);background-color: rgb(255,255,255);font-size: 16px;font-family: avertaregular;\">Sample Papers for thorough revision</span>&nbsp;</li>\n</ul>\n', 1, 0, 543, '1', NULL, NULL, NULL, 0, 0.00, 360.00, 400.00, 0.00, '9789326196666', 49011010, '9789326196666', 0, '', '', '', '', 'ARIHANT ALL IN ONE CLASS 9 ENGLISH LANGUAGE & LITERATURE', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1, 'erp_textbooks', 348, '2026-02-28 05:39:28', '2026-02-28 10:07:04', NULL, NULL),
