(34, 43, 'INDIRA NATIONAL SCHOOL, PARANDWADI', 'indira-national-school-parandwadi', 'CBSE', 1000, 'Indira National School, Parandwandi focus is to mould every child from INS to be a responsible citizen of the world, with strong fundamentals and deep rooted values, to see them through the challenges of life.\n', 'INS-Parandwadi', 'S.No. 64,65, Gat No. 276, At Post :, Parandwadi Rd, near Somatne phata', 101, 1568, 17479, '410506', 'Mrs. Uma Pradeep', '9890533272', 'infoparandwadi@indiranationalschool.ac.in', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:35'),
(35, 43, 'ROSARY SCHOOL, BIBWEWADI (STATE BOARD)', 'rosary-school-bibwewadi-state-board', 'STATE BOARD', 1800, 'Rosary School is a co-educational school that educates students from nursery to class XII. Affiliated to the Council for the Indian School Certificate Examinations, New Delhi, School aims to develop sensitivity towards the environment among its students.', 'ROSARY111', 'Satara Rd, opp. Gandharva Lawns, Vasant Baug, Vasant Baug Society, Katraj, Pune', 101, 1568, 17479, '411047', 'Ms. Shalini Noronha', '24219306', 'rosary@rosaryedu.org', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:35'),
(36, 43, 'G.G.I.S. ATHA', 'ggis-atha', 'CBSE', 1500, 'The best International Pre-school that is designed to give your child a strong, solid, happy beginning in the world of education!', 'GGIS-AATHA-CHINCHWAD', 'Ganga Aashiyana Commercial Building, 1st Floor, Thergaon, Chinchwad, Pune - 411019', 101, 1568, 17479, ' 411019', 'Mrs. Neha Marathe Sahastrabudhe', '8806497555', 'admissions@myggis.org', 'e10adc3949ba59abbe56e057f20f883e', 'active', 0, NULL, 1, 1, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:37'),
(37, 43, 'G.G.I.S. BAVDHAN', 'ggis-bavdhan', 'CBSE', 150, 'The best International School in Bavdhan that is designed to give your child a strong, solid, happy beginning in the world of education!', '1130198', 'Ganga Legends County, Next to DSK Ranwara, Bavdhan, Pune - 411021', 101, 1568, 17479, '411021', 'Sukhvinder Kaur', '9172263008', 'admin@myggis.org', '', 'active', 0, NULL, 1, 1, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:38'),
(38, 43, 'G.G.I.S. ATHA, PIMPRI', 'ggis-atha-pimpri', 'CBSE', 150, 'GIS ATHA - the pre school wing of GG International School is here to give your child the right beginning and a happy early childhood.', '1130198 ', ' CID Colony, Rahatani, Pimpri-Chinchwad, Maharashtra 411027', 101, 1568, 17479, ' 411027', 'Ramanjit Ghuman', '9503087770', 'admissions@myggis.org', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:38'),
(39, 43, 'ASHWINI INTERNATIONAL SCHOOL, TATHAWADE', 'ashwini-international-school-tathawade', 'ICSE', 700, 'Ashwini International School is a new venture of an age old organization - Vimal Education Society which was started in June 2012, with its maiden batch. At present, the school is having Pre-Primary, Primary and Higher-Primary section and will grow in a phased manner upto Std XII.\nWe impart immeasurable values to the students. The curriculum followed is flexible and enables the new trends in education to take root in the existing system. This helps in keeping pace with the rapidly changing educational scenario. In Ashwini International School language is not a barrier, as love, discipline and English works. The British left us â€“ Discipline, Time and Style in addition to our age old culture and heritage which goes untouched by the present generation. We at Ashwini International School have taken up the task of bringing back the combination into the lives of the coming generation.\n\n', 'ASHWINI001', 'Ashwini International School 58/1, Behind Indira College, Near Ganga Cypress, Tathawade, Pune-411033.', 101, 1568, 17479, '411033', 'Ms. Ila Rathore', '7276023177', 'contacts@ashwini', '', 'active', 0, NULL, 0, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:40'),
(40, 43, 'KAVERI INTERNATIONAL SCHOOL, LOHEGAON', 'kaveri-international-school-lohegaon', 'ICSE', 1500, '\"Kaveri International School offers holistic education based on ICSE curriculum using modern teaching techniques from L.K.G To 8th Std.\"', '789456', 'S. No. 35, Vadgaon Shinde Road, Lohegaon, Tal. Haveli, Pune 411 047.', 101, 1568, 17479, '411047', 'Mrs. Kamini Saxena', '8446271222', 'admissionskis@kaveri.edu.in', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:41'),
(41, 43, 'ABHINAV ENGLISH SCHOOL, KATRAJ', 'abhinav-english-school-katraj', 'CBSE', 750, 'The Abhinav Campus at Narhe , constitutes of 5 acres out of which 2 acres is allotted to Abhinav English School (CBSE). The magnificient building posses spacious classrooms, labs, Multipurpose hall, Recreation Center , Learning Resource Center, Huge Play Ground and other facilities for the students.', '1130340', 'Sr.No. 23/3/2/2, A/P- Narhe,Katraj â€“ Mumbai Bypass Highway,  Tal â€“ Haveli', 101, 1568, 17479, '411041', 'Dr. Mrs Vaishali Kulkarni', '7447443601', 'abhinavschool19@yahoo.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:42'),
(42, 43, 'ABHINAV ENGLISH SCHOOL, LOTUS', 'abhinav-english-school-lotus', 'CBSE', 150, 'Abhinav Lotus English School is located in Bibewadi, Pune. It was established in 1999. This school follows the State board. The school has English medium.', '1130340', 'Ganraj Heights Kashinath Patilnagar, Dhankawadi', 101, 1568, 17479, '411043', 'Mrs. Prajakta Jagtap', '8888861738', 'abhinavlotus@rediffmail.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:43'),
(43, 43, 'ABHINAV ENGLISH SCHOOL, BHOR', 'abhinav-english-school-bhor', 'CBSE', 500, 'The Abhinav Campus at Narhe , constitutes of 5 acres out of which 2 acres is allotted to Abhinav English School (CBSE). The magnificient building posses spacious classrooms, labs, Multipurpose hall, Recreation Center , Learning Resource Center, Huge Play Ground and other facilities for the students.', '1130340', 'Sr.No. 23/3/2/2, A/P- Narhe,  Katraj â€“ Mumbai Bypass Highway,  Tal â€“ Haveli,', 101, 1568, 17479, '411041', 'Dr. Mrs Vaishali Kulkarni', '7447443601', 'abhinavschool19@yahoo.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:44'),
(44, 43, 'ROSARY SCHOOL, KONDHWA (STATE BOARD)', 'rosary-school-kondhwa-state-board', 'STATE BOARD', 1800, 'The school is affiliated to the Maharashtra State Board for Secondary and Higher Education.\nStudents from this school appear for the SSC (Senior Secondary Certificate) Examinations after Class 10. ', '1115193', 'S. No. 69/1 , Slunke Vihar Rd, Salunke Vihar, Salunkhe Vihar Society, Kondhwa, Pune', 101, 1568, 17479, '411040', 'Ms. Shalini Noronha', '9970178967', 'rosary1958@gmail.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:47'),
(45, 43, 'ROSARY SCHOOL, VIMAN NAGAR (STATE BOARD)', 'rosary-school-viman-nagar-state-board', 'STATE BOARD', 1000, 'The Rosary Education Group functions along the lines of an ever-evolving educational system that focuses on Holistic moulding of the students. We at the Rosary Education Group have academic programmes that are technologically balanced, well-researched and are powered by state-of-the-art infrastructure and facilities. Our students acquire education rooted in our ethics and are empowered to be global citizens of tomorrow. Rosary also has a vast pool of intellectual capital.', 'ROSARY103', 'Tasmac Rd, Opp. Neco Gardens, Viman Nagar, Viman Nagar, Pune', 101, 1568, 17479, '411001', 'Ms. Usha Pereira', '26134668', 'info@rosaryedu.org', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:48'),
(46, 43, 'ROSARY SCHOOL, BIBWEWADI (ICSE)', 'rosary-school-bibwewadi-icse', 'ICSE', 750, 'The Rosary Education Group functions along the lines of an ever-evolving educational system that focuses on Holistic moulding of the students. We at the Rosary Education Group have academic programmes that are technologically balanced, well-researched and are powered by state-of-the-art infrastructure and facilities. Our students acquire education rooted in our ethics and are empowered to be global citizens of tomorrow. Rosary also has a vast pool of intellectual capital. This is what sets the school apart in the growing milieu of schools in a society which is getting more and more border-less by the day. We are easily one of the best schools in Pune, Maharashtra, India.', 'ROSARY102', 'Near City Pride, Upper Indira Nagar Rd, Bibwewadi, Pune, , Pune', 101, 1568, 17479, ' 411047', ' Ms. Shalini Noronha', '9326551767', 'rosaryedu@gmail.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:49'),
(47, 43, 'ROSARY SCHOOL, WARJE (ICSE)', 'rosary-school-warje-icse', 'ICSE', 500, 'The Rosary Education Group functions along the lines of an ever-evolving educational system that focuses on Holistic moulding of the students. We at the Rosary Education Group have academic programmes that are technologically balanced, well-researched and are powered by state-of-the-art infrastructure and facilities. Our students acquire education rooted in our ethics and are empowered to be global citizens of tomorrow. Rosary also has a vast pool of intellectual capital. This is what sets the school apart in the growing milieu of schools in a society which is getting more and more border-less by the day. We are easily one of the best schools in Pune, Maharashtra, India.', 'ROSARY101', ' Rosary International School, Atul Nagar, Warje, Pune, Maharashtra 411058', 101, 1568, 17479, '411058', 'MS. Usha Pereira', '64002892', 'rosary@rosaryedu.org', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:49'),
(48, 43, 'GURUKUL SCHOOL(S.E.S.), ASHOK NAGAR', 'gurukul-schoolses-ashok-nagar', 'CBSE', 400, 'The Saraswati Educational Society is the brainchild of people passionate about children and their development. This was further conceived and conceptualized to merge the ancient â€˜gurukulâ€™ system with the emerging trends of the modern-day education system. Strong determination, persistence, faith, and sincere efforts of like-minded enthusiasts further led to the foundation of the Saraswati Educational Society, the authority under which SES GURUKUL operates.', '1130050 ', '26, Sinchan Nagar, Ashok Nagar, Pune, Maharashtra 411016', 101, 1568, 17479, '411016', 'Seema Hoskote', '7709961133', 'gurukulpuneprincipal@gmail.com', 'e10adc3949ba59abbe56e057f20f883e', 'active', 0, NULL, 0, 1, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:50'),
(49, 43, 'ROSARY HIGH SCHOOL, CAMP (ICSE)', 'rosary-high-school-camp-icse', 'ICSE', 750, 'Rosary School is a co-educational school that educates students from nursery to class XII. Affiliated to the Council for the Indian School Certificate Examinations, New Delhi, School aims to develop sensitivity towards the environment among its students.', 'MA179', 'No.14/3, Dr. Ambedkar Road,  Camp, Pune, Maharashtra 411001', 101, 1568, 17479, '411001', 'Ms.Usha Pereira', '32319420', 'info@rosaryedu.org', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:51'),
(50, 43, 'DR. VIKHE PATIL MEMORIAL SCHOOL, SENAPATI BAPAT ROAD', 'dr-vikhe-patil-memorial-school-senapati-bapat-road', 'CBSE', 2000, 'Dr Vikhe Patil Memorial School helps students in becoming successful managers.Being affiliated to the University of Pune, the school is amongst the best schools in Pune which is committed to provide quality learning and education to its students. It is affiliated to the Central Board of Secondary Education. This School provides the highest quality educational experience to all its childrenâ€™s.', '1130119 ', 'Off Senapati Bapat Road, Patrakar Nagar Rd, Gokhalenagar, Pune, Maharashtra 411016', 101, 1568, 17479, '411016', 'Ms. Mrinalini', '25658170', 'contact@vpmspune.org', '', 'active', 0, NULL, 0, 1, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:53'),
(51, 43, 'DR. D.Y. PATIL PUBLIC SCHOOL, PIMPRI', 'dr-dy-patil-public-school-pimpri', 'CBSE', 1200, 'Dr. D. Y. Patil Public School has been started and operates with the prime purpose of building young minds to spearhead a dynamic future globally. In this school the learning environment is safe , Indian values are embedded and independent thinkers are created. We inspire all our students and teachers to learn, hope, dream, appreciate, create, innovate, excel and contribute. The school also inculcates in every child, love for the rich cultural heritage of India.', '1130679', 'Sant Tukaram Nagar, Pimpri Colony, Pimpri-Chinchwad, Maharashtra 411018', 101, 1568, 17479, '411018', 'Mrudula M. Mahajan', '27805891', 'info.publicschool@dypvp.edu.in', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:54'),
(52, 43, 'CHALLENGER PUBLIC SCHOOL, PIMPLE SAUDGAR', 'challenger-public-school-pimple-saudgar', 'CBSE', 650, 'CPS emphasizes the importance of â€˜Learning by Doingâ€™. We believe learning should be interesting and practical. Almost every subject has Kits â€“ Maths, Science, Environmental Science, Robotics etc. We intend to draw out and nurture their natural abilities, be it artistic, scientific or linguistic. A strong emphasis on holistic growth is emphasized with subjects like Public Speaking, Creative Writing, Theater, Music, Dance and numerous internal and external competitions we provide.', '1130951', '177/1 2, Shiv Sai Ln, Empire Estate Phase 1, Phase-II, Pimple Saudagar, Pune, Maharashtra 411027', 101, 1568, 17479, '411027', 'Mrs. Sushama Upadhye', '779600200', 'principal_cpspune@rediffmail.com', '', 'active', 0, NULL, 0, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:55'),
(54, 43, 'G.G. INTERNATIONAL SCHOOL, VALLABH NAGAR', 'gg-international-school-vallabh-nagar', 'CBSE', 2000, '\"GG International School (Best CBSC international school In Pune) is an ISO Certified, co-educational and CBSE affiliated Senior Secondary international School in Pimpri which has been in existence since 2007. The international school in pimpri has time and again won awards, ranked among the best schools in PCMC and served more than 5000 students till now. MYGGIS best international school in pune realized our dream of creating a community of academicians, parents and students who are committed towards self-realization and now are all set to fly higher with best international school in pune.\"', '11301981', '174-177, Swarganga, Vallabhnagar, Near The Muslim Co-operative Bank, Pimpri Colony, Pune', 101, 1568, 17479, '411018', 'Dr. Seuss', '9503087795', 'admin@myggis.org', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:39:56'),
(55, 43, 'DR KALMADI SHAMARAO HIGH SCHOOL, AUNDH', 'dr-kalmadi-shamarao-high-school-aundh', 'CBSE', 800, 'Kannada Sangha\'s â€˜Kaveri Group of Institutesâ€™ runs a group of dedicated educational institutions that provide excellent education and a conducive environment for the all-around development at all the levels of school, junior college, undergraduate and post graduate level education.', '1111098', 'Kannada Sanghaâ€™s Kaveri Group of Institutes, S. No. 36, Plot no. 3, Erandwane, Ganeshnagar Road, Pune-411038', 101, 1568, 17479, '411038', 'Mrs. Lakshmi Gandhi', '25436893', 'frontoffice@kannadasanghapune.org', '', 'active', 0, NULL, 0, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:40:03'),
(56, 43, 'DARSHAN ACADEMY, CHINCHWAD', 'darshan-academy-chinchwad', 'CBSE', 750, 'Students in Darshan Academies follow a full academic program designed to meet the state requirements and standards. The curriculum is of the highest quality and students are expected to achieve the maximum standard of academic excellence. In India they are prepared for the secondary and senior secondary C.B.S.E. examinations.', '11306441', 'CTS No.4510 1, Empire Estate Phase 1, Chinchwad, Pune, Maharashtra 411019', 101, 1568, 17479, '411019', 'Mrs Rangoli Saxena', '27414545', 'info@darshanacademy.org', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:40:03'),
(57, 43, 'D Y PATIL HIGH SCHOOL - AMBI, TALEGAON', 'd-y-patil-high-school-ambi-talegaon', 'CBSE', 1000, 'At D Y Patil High School (DYPHS), we adopt the countryâ€™s richest and longest serving academic board curriculum, the Delhi based, The Central Board of Secondary Education(CBSE).', '330671', 'D.Y.Patil Technical Campus, 124 & 126, Ambi MIDC Road Tal Maval, Talegaon Dabhade, Maharashtra 410506', 101, 1568, 17479, '410506', 'Mr. Alexander Coates Reid', '9850325030', 'dypatil@gmail.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:40:04'),
(58, 43, 'ALARD PUBLIC SCHOOL, HINJEWADI', 'alard-public-school-hinjewadi', 'CBSE', 400, '-', '01130586', 'Survey No. 50, Marunje, near Rajiv Gandhi, IT Park, Hinjawadi, Pune, Maharashtra 411057', 101, 1568, 17479, '411057', 'Dr. L.R. Yadav, Founder', '9579279099', 'info@alardpublicschool.com', '', 'active', 0, NULL, 0, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:40:05'),
(59, 43, 'ABHINAV ENGLISH SCHOOL, AMBEGAON', 'abhinav-english-school-ambegaon', 'CBSE', 500, 'The abhinav campus at ambegaon constitutes of 2 acres out of the total 60 acres area under the educational institutes of the society. The magnificent school building houses spacious classrooms, labs, multi-purpose hall and other facilities for the students.', '1130341', 'Katraj-Dehu Rd Bypass, Ambegaon BK, Pune, Maharashtra 411046', 101, 1568, 17479, '411046', 'Varsha Sharma', '9146187406', 'aesemsjc@gmail.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:40:06'),
(60, 43, 'SPICER HIGHER SECONDARY SCHOOL', 'spicer-higher-secondary-school', 'ICSE', 4500, 'AUNDH', ' DELISCE810', 'Aundh Rd, Ward No. 8, Aundh Gaon, Ganeshkhind, Pune, Maharashtra 411007', 101, 1568, 17479, '411007', 'Mr. Shashikant M. Gaikwad', '8087845841', 'principal.spicerschool@gmail.com', '', 'active', 0, NULL, 0, 1, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:40:07'),
(61, 43, 'KENDRIYA VIDYALAYA GANESHKHIND, PUNE', 'kendriya-vidyalaya-ganeshkhind-pune', 'CBSE', 1500, 'Kendriya Vidyalaya Ganeshkhind is a school located in Pune, India. It gives education from Class I to XII covering children of age 5 to 17. ', '1100013', 'Vidyapeeth Rd, Armament Colony, Ganeshkhind, Pune, Maharashtra 411007', 101, 1568, 17479, '411007', 'Ms Shabana Khan', '25691108', 'kvganeshkhindpune07@gmail.com', '', 'active', 0, NULL, 1, 0, 1, 0, '2026-02-28 11:03:38', '2026-02-28 12:40:08'),
